const BUF_SIZE = 4096;
let buf = crypto.randomBytes(BUF_SIZE);
let bufOffset = 0;

function cryptoRandom(): number {
  if (bufOffset + 8 > BUF_SIZE) {
    buf = crypto.randomBytes(BUF_SIZE);
    bufOffset = 0;
  }
  const hi = buf.readUInt32BE(bufOffset);
  const lo = buf.readUInt32BE(bufOffset + 4);
  bufOffset += 8;
  return (((hi >>> 5) * 0x4000000 + (lo >>> 6)) / 0x20000000000000);
}

function bezierPath(start: Point, end: Point, steps: number): Point[] {
  // Two randomized control points create a natural arc
  const cp1 = {
    x: start.x + (end.x - start.x) * 0.3 + cryptoRandom() * 100 - 50,
    y: start.y + (end.y - start.y) * 0.3 + cryptoRandom() * 100 - 50,
  };
  const cp2 = {
    x: start.x + (end.x - start.x) * 0.7 + cryptoRandom() * 100 - 50,
    y: start.y + (end.y - start.y) * 0.7 + cryptoRandom() * 100 - 50,
  };
  // Sample N points along the curve
  return Array.from({ length: steps }, (_, i) => {
    const t = i / (steps - 1);
    return cubicBezier(start, cp1, cp2, end, t);
  });
}
